Move `useState` outside the conditional:

```jsx
// ❌ Wrong
function Component({ show }) {
if (show) {
const [state, setState] = useState(0); // Violation!
}
}

// ✅ Correct
function Component({ show }) {
const [state, setState] = useState(0);
if (!show) return null;
// Use state here...
}
```

